import{_ as e,o as l,c as a,a2 as i}from"./chunks/framework.D36jym0Z.js";const y=JSON.parse('{"title":"TokenPilot Benchmarks","description":"","frontmatter":{},"headers":[],"relativePath":"plugin-catalog/tokenpilot/benchmarks.md","filePath":"plugin-catalog/tokenpilot/benchmarks.md","lastUpdated":1784542960000}'),s={name:"plugin-catalog/tokenpilot/benchmarks.md"};function n(r,t,o,d,g,h){return l(),a("div",null,[...t[0]||(t[0]=[i('<h1 id="tokenpilot-benchmarks" tabindex="-1">TokenPilot Benchmarks <a class="header-anchor" href="#tokenpilot-benchmarks" aria-label="Permalink to &quot;TokenPilot Benchmarks&quot;">​</a></h1><p>TokenPilot is evaluated on two benchmarks: <strong>PinchBench</strong> and <strong>Claw-Eval</strong>. Both measure agent task success and token efficiency.</p><h2 id="evaluation-setup" tabindex="-1">Evaluation Setup <a class="header-anchor" href="#evaluation-setup" aria-label="Permalink to &quot;Evaluation Setup&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Parameter</th><th style="text-align:left;">Value</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Model</strong></td><td style="text-align:left;">GPT-5.4-mini (OpenClaw)</td></tr><tr><td style="text-align:left;"><strong>Pricing</strong></td><td style="text-align:left;">$1.10/M input, $4.40/M cached input, $8.80/M output</td></tr><tr><td style="text-align:left;"><strong>Modes</strong></td><td style="text-align:left;">Isolated (fresh session per task) and Continuous (shared session)</td></tr><tr><td style="text-align:left;"><strong>TokenPilot mode</strong></td><td style="text-align:left;">Normal</td></tr></tbody></table><h3 id="isolated-vs-continuous" tabindex="-1">Isolated vs. Continuous <a class="header-anchor" href="#isolated-vs-continuous" aria-label="Permalink to &quot;Isolated vs. Continuous&quot;">​</a></h3><ul><li><strong>Isolated</strong>: Each task runs in a fresh session. No cross-task context accumulation. Tests single-task behavior.</li><li><strong>Continuous</strong>: Tasks run in a shared session. Context accumulates across tasks. Tests TokenPilot&#39;s ability to manage growing context.</li></ul><p>TokenPilot&#39;s benefits are most visible in <strong>continuous mode</strong>, where context accumulation and cache reuse matter most.</p><h2 id="pinchbench" tabindex="-1">PinchBench <a class="header-anchor" href="#pinchbench" aria-label="Permalink to &quot;PinchBench&quot;">​</a></h2><p>PinchBench measures performance across 11 task categories: Productivity, Research, Writing, Coding, Analysis, CSV Analysis, Log Analysis, Meeting Analysis, Memory, Skills, and Integrations.</p><p><a href="https://drive.google.com/drive/u/0/folders/11hrLzrreLnBFLz5bttx11lGUcO39QkLc" target="_blank" rel="noreferrer">PinchBench results and logs</a></p><h3 id="continuous-mode-where-tokenpilot-excels" tabindex="-1">Continuous Mode (where TokenPilot excels) <a class="header-anchor" href="#continuous-mode-where-tokenpilot-excels" aria-label="Permalink to &quot;Continuous Mode (where TokenPilot excels)&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Method</th><th style="text-align:right;">Overall Score</th><th style="text-align:right;">Cache Read (M)</th><th style="text-align:right;">Cache Miss (M)</th><th style="text-align:right;">Output (M)</th><th style="text-align:right;">Cost ($)</th></tr></thead><tbody><tr><td style="text-align:left;">Vanilla</td><td style="text-align:right;">79.2</td><td style="text-align:right;">25.015</td><td style="text-align:right;">5.943</td><td style="text-align:right;">0.202</td><td style="text-align:right;">7.24</td></tr><tr><td style="text-align:left;">LLMLingua-2</td><td style="text-align:right;">73.8</td><td style="text-align:right;">20.574</td><td style="text-align:right;">2.183</td><td style="text-align:right;">0.194</td><td style="text-align:right;">4.06</td></tr><tr><td style="text-align:left;">SelectiveContext</td><td style="text-align:right;">74.0</td><td style="text-align:right;">25.475</td><td style="text-align:right;">2.608</td><td style="text-align:right;">0.196</td><td style="text-align:right;">4.75</td></tr><tr><td style="text-align:left;">LCM</td><td style="text-align:right;">77.0</td><td style="text-align:right;">18.708</td><td style="text-align:right;">2.417</td><td style="text-align:right;">0.222</td><td style="text-align:right;">4.21</td></tr><tr><td style="text-align:left;">Keep-Last-N</td><td style="text-align:right;">79.1</td><td style="text-align:right;">18.117</td><td style="text-align:right;">4.481</td><td style="text-align:right;">0.209</td><td style="text-align:right;">5.66</td></tr><tr><td style="text-align:left;">MemOS</td><td style="text-align:right;">80.9</td><td style="text-align:right;">30.859</td><td style="text-align:right;">8.939</td><td style="text-align:right;">0.308</td><td style="text-align:right;">10.41</td></tr><tr><td style="text-align:left;"><strong>TokenPilot</strong></td><td style="text-align:right;"><strong>81.3</strong></td><td style="text-align:right;"><strong>8.551</strong></td><td style="text-align:right;"><strong>1.549</strong></td><td style="text-align:right;"><strong>0.219</strong></td><td style="text-align:right;"><strong>2.79</strong></td></tr></tbody></table><p>TokenPilot achieves:</p><ul><li><strong>67.4% fewer input tokens</strong> vs. Vanilla (cache miss: 1.549M vs. 5.943M)</li><li><strong>61.5% lower cost</strong> vs. Vanilla ($2.79 vs. $7.24)</li><li><strong>Best overall score</strong> (81.3)</li><li><strong>Lowest cache miss</strong> and best cache reuse</li></ul><h3 id="isolated-mode" tabindex="-1">Isolated Mode <a class="header-anchor" href="#isolated-mode" aria-label="Permalink to &quot;Isolated Mode&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Method</th><th style="text-align:right;">Overall Score</th><th style="text-align:right;">Cache Read (M)</th><th style="text-align:right;">Cache Miss (M)</th><th style="text-align:right;">Output (M)</th><th style="text-align:right;">Cost ($)</th></tr></thead><tbody><tr><td style="text-align:left;">Vanilla</td><td style="text-align:right;">80.5</td><td style="text-align:right;">6.184</td><td style="text-align:right;">8.753</td><td style="text-align:right;">0.285</td><td style="text-align:right;">8.31</td></tr><tr><td style="text-align:left;">MemoBrain</td><td style="text-align:right;">78.1</td><td style="text-align:right;">10.200</td><td style="text-align:right;">2.107</td><td style="text-align:right;">0.233</td><td style="text-align:right;">3.36</td></tr><tr><td style="text-align:left;"><strong>TokenPilot</strong></td><td style="text-align:right;"><strong>81.0</strong></td><td style="text-align:right;"><strong>8.893</strong></td><td style="text-align:right;"><strong>1.933</strong></td><td style="text-align:right;"><strong>0.244</strong></td><td style="text-align:right;"><strong>3.22</strong></td></tr></tbody></table><p>Even in isolated mode, TokenPilot achieves the best overall score and lowest cost.</p><h2 id="claw-eval" tabindex="-1">Claw-Eval <a class="header-anchor" href="#claw-eval" aria-label="Permalink to &quot;Claw-Eval&quot;">​</a></h2><p>Claw-Eval measures performance across 12 task categories: Workflow, Operations, Finance, Office QA, Communication, Productivity, Operations, Safety, Terminal, Multimodal, and Others.</p><p><a href="https://drive.google.com/drive/u/0/folders/1694iNhrAzc8JtWTiUUALXsopZ8s6suCS" target="_blank" rel="noreferrer">Claw-Eval results and logs</a></p><h3 id="continuous-mode" tabindex="-1">Continuous Mode <a class="header-anchor" href="#continuous-mode" aria-label="Permalink to &quot;Continuous Mode&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Method</th><th style="text-align:right;">Overall Score</th><th style="text-align:right;">Cache Read (M)</th><th style="text-align:right;">Cache Miss (M)</th><th style="text-align:right;">Output (M)</th><th style="text-align:right;">Cost ($)</th></tr></thead><tbody><tr><td style="text-align:left;">Vanilla</td><td style="text-align:right;"><strong>63.4</strong></td><td style="text-align:right;">709.845</td><td style="text-align:right;">21.981</td><td style="text-align:right;">2.622</td><td style="text-align:right;">81.52</td></tr><tr><td style="text-align:left;">MemoBrain</td><td style="text-align:right;">57.9</td><td style="text-align:right;">47.497</td><td style="text-align:right;">13.990</td><td style="text-align:right;">1.134</td><td style="text-align:right;">19.16</td></tr><tr><td style="text-align:left;">AgentSwing</td><td style="text-align:right;">62.2</td><td style="text-align:right;">53.776</td><td style="text-align:right;">10.027</td><td style="text-align:right;">0.907</td><td style="text-align:right;">15.63</td></tr><tr><td style="text-align:left;"><strong>TokenPilot</strong></td><td style="text-align:right;"><strong>60.8</strong></td><td style="text-align:right;"><strong>21.430</strong></td><td style="text-align:right;"><strong>9.928</strong></td><td style="text-align:right;"><strong>0.338</strong></td><td style="text-align:right;"><strong>10.58</strong></td></tr></tbody></table><p>TokenPilot achieves:</p><ul><li><strong>95.7% fewer input tokens</strong> vs. Vanilla (cache miss: 9.928M vs. 21.981M)</li><li><strong>87.0% lower cost</strong> vs. Vanilla ($10.58 vs. $81.52)</li><li><strong>Massive cache read reduction</strong> (21.43M vs. 709.85M — 97% reduction)</li></ul><h3 id="isolated-mode-1" tabindex="-1">Isolated Mode <a class="header-anchor" href="#isolated-mode-1" aria-label="Permalink to &quot;Isolated Mode&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Method</th><th style="text-align:right;">Overall Score</th><th style="text-align:right;">Cache Read (M)</th><th style="text-align:right;">Cache Miss (M)</th><th style="text-align:right;">Output (M)</th><th style="text-align:right;">Cost ($)</th></tr></thead><tbody><tr><td style="text-align:left;">Vanilla</td><td style="text-align:right;"><strong>64.5</strong></td><td style="text-align:right;">9.429</td><td style="text-align:right;">4.637</td><td style="text-align:right;">0.216</td><td style="text-align:right;">5.16</td></tr><tr><td style="text-align:left;">TokenPilot</td><td style="text-align:right;">63.1</td><td style="text-align:right;"><strong>4.436</strong></td><td style="text-align:right;"><strong>1.154</strong></td><td style="text-align:right;">0.239</td><td style="text-align:right;"><strong>2.27</strong></td></tr></tbody></table><p>TokenPilot achieves the lowest cache miss and lowest cost in isolated mode as well.</p><h2 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h2><ol><li><strong>Cache miss is dramatically lower</strong>: TokenPilot&#39;s stable prefix ensures consistent cache hits.</li><li><strong>Cost scales better</strong>: Vanilla cost grows with session length; TokenPilot cost stays flat.</li><li><strong>Quality is maintained</strong>: Task success is competitive or better across both benchmarks.</li><li><strong>Continuous is where it shines</strong>: The longer the session, the bigger TokenPilot&#39;s advantage.</li></ol><h2 id="reproducing-results" tabindex="-1">Reproducing Results <a class="header-anchor" href="#reproducing-results" aria-label="Permalink to &quot;Reproducing Results&quot;">​</a></h2><p>See <a href="https://github.com/zjunlp/LightMem2/blob/main/experiments/README.md" target="_blank" rel="noreferrer">experiments/README.md</a> in the repository for:</p><ul><li>Environment setup</li><li>Data download links</li><li>Runner commands</li><li>Output directory structure</li></ul>',32)])])}const x=e(s,[["render",n]]);export{y as __pageData,x as default};
